const BIH_KEYWORDS = [
  'excavator', 'attachment', 'bucket', 'thumb', 'ripper', 'auger',
  'coupler', 'quick hitch', 'compactor', 'breaker', 'hydraulic hammer',
  'heavy equipment', 'earthwork', 'grading', 'cat', 'komatsu',
  'volvo', 'hitachi', 'liebherr', 'doosan', 'hyundai'
];

const REGION_KEYWORDS = [
  'ontario', 'toronto', 'gta', 'peel', 'york', 'durham', 'halton',
  'brampton', 'mississauga', 'markham', 'oakville', 'hamilton',
  'vaughan', 'barrie', 'kingston', 'ottawa'
];

const results = [];

for (const item of $input.all()) {
  const d = item.json;
  const text = `${d.title || ''} ${d.content || d.contentSnippet || d.description || ''}`.toLowerCase();

  const kw_hit = BIH_KEYWORDS.filter(k => text.includes(k));
  if (kw_hit.length === 0) continue;

  const region_found = REGION_KEYWORDS.find(r => text.includes(r));

  const raw_id = d.guid || d.link || d.id || String(Date.now());
  const listing_id = 'CB-' + raw_id.replace(/[^a-zA-Z0-9]/g, '').slice(-60);

  const out = {
    listing_id,
    title: (d.title || 'Untitled').slice(0, 500),
    region: region_found
      ? region_found.charAt(0).toUpperCase() + region_found.slice(1)
      : 'Canada',
    source_url: (d.link || '').slice(0, 500),
    keywords_hit: kw_hit.slice(0, 20)
  };

  results.push({ json: out });
}

return results;

const tenders = $input.item.json.tenders || [];
if (tenders.length === 0) return [];

const lines = tenders.map(t =>
  `📋 *${(t.title || '').slice(0, 80)}*\n` +
  `📍 ${t.region || ''}` +
  (t.deadline ? ` | ⏰ ${t.deadline}` : '') + '\n' +
  (t.source_url ? `🔗 ${t.source_url}` : '') +
  (t.keywords_hit && t.keywords_hit.length ? `\n🏷 ${t.keywords_hit.join(', ')}` : '')
).join('\n\n');

const message = `🚨 *BIH — ${tenders.length} 条新标讯*\n\n${lines}\n\n_by n8n WF5_`;
return [{ json: { message } }];
